sql:
SELECT AVG(average_price) AS Average_Housing_Price 
FROM average_houses 
WHERE data_quality = 'high' AND region_id = 1;

SELECT years.year_name, tax_rates.tax_rate
FROM years
JOIN tax_rates ON years.year_id = tax_rates.year_id;

SELECT COUNT(DISTINCT user_id) 
FROM access_logs 
WHERE access_date = '2023-05-01';

SELECT *
FROM local_taxes
WHERE year_id = 2020 AND region_id = 1;

SELECT year_id, average_price 
FROM housing_data
WHERE data_id = 1;

SELECT average_id
FROM average_houses
WHERE average_price > 500000;

SELECT COUNT(DISTINCT user_id) AS TotalUsers
FROM access_logs
WHERE data_id IN (
    SELECT data_id
    FROM housing_data
);

SELECT forecast_value 
FROM forecast_results
WHERE model_id = 0 AND year_id = 1 AND forecasted = 1;

SELECT LN(CAST(average_price AS REAL)) AS log_average_price
FROM average_houses
WHERE data_quality = 'high';

SELECT ds.source_name, lt.local_taxes
FROM data_sources ds, local_taxes lt
ORDER BY ds.source_name ASC;

external_knowledge:
- 'official inquiries' refer to access logs of 'city officials';
- 'last year' refers to the period between January 1, 2022, and December 31, 2022;
- 'housing and tax adjustments' are represented by average house prices and tax rate increases recorded in the database.

- "beacons of truth" refers to high data quality;
- "populace exceeds the half-million mark" indicates population greater than 500,000;
- "year of our current focus, 2022" signifies the year being analyzed is 2022;
- "tales told by their data are genuine and not of the prophetic ilk" means the data is actual (forecasted = 0).

sql:
SELECT year_id, AVG(average_price)
FROM average_houses
GROUP BY year_id;
